-- Seed oficial estructurado para Album Mundial Ammycita.
-- Fuente declarada por registro: Panini official checklist 2026.
-- Nota: PENDING001 queda eliminado de la data visible.
begin;

delete from public.user_stickers where sticker_id in (select id from public.stickers where code = 'PENDING001');
delete from public.stickers where code = 'PENDING001';

on conflict (page_number) do update set
  title = excluded.title,
  section = excluded.section,
  description = excluded.description;

on conflict (code) do update set
  number = excluded.number,
  album_page = excluded.album_page,
  section = excluded.section,
  country = excluded.country,
  name = excluded.name,
  type = excluded.type,
  rarity = excluded.rarity,
  verified = excluded.verified,
  source = excluded.source,
  image_url = excluded.image_url;

commit;

